export const MUNICIPALITIES: Municipality[] = RAW.map(([bfs, name, canton, factor, churchProtestant, churchRoman]) => ({
  bfs,
  name,
  canton: canton as CantonCode,
  factor,
  churchProtestant,
  churchRoman,
}));

export function municipalitiesForCanton(canton: CantonCode): Municipality[] {
  return MUNICIPALITIES.filter((m) => m.canton === canton);
}

export function municipalityByBfs(bfs: number): Municipality | undefined {
  return MUNICIPALITIES.find((m) => m.bfs === bfs);
}
